    // ---------------------------------------------------------------------------
    // parse_file_references
    // ---------------------------------------------------------------------------

    #[test]
    fn parse_file_refs_single() {
        let refs = parse_file_references("hello @src/main.rs world");
        assert_eq!(refs, vec!["src/main.rs"]);
    }

    #[test]
    fn parse_file_refs_multiple() {
        let refs = parse_file_references("@a/b @c/d.txt");
        assert_eq!(refs.len(), 2);
        assert!(refs.contains(&"a/b".to_string()));
        assert!(refs.contains(&"c/d.txt".to_string()));
    }

    #[test]
    fn parse_file_refs_ignores_slash_commands() {
        let refs = parse_file_references("/new @src/main.rs");
        assert_eq!(refs, vec!["src/main.rs"]);
    }

    #[test]
    fn parse_file_refs_empty() {
        let refs = parse_file_references("hello world");
        assert!(refs.is_empty());
    }

    #[test]
    fn parse_file_refs_max_8() {
        let input = "@a/b @c/d @e/f @g/h @i/j @k/l @m/n @o/p @q/r";
        let refs = parse_file_references(input);
        assert!(refs.len() <= 8);
    }

    #[test]
    fn parse_file_refs_accepts_simple_names() {
        let refs = parse_file_references("@hello");
        assert_eq!(refs, vec!["hello"]);
    }

