    fn palette_fuzzy_match_toggle_finds_all_toggles() {
        let results = fuzzy_match_palette_commands("toggle", 10);
        assert!(results.len() >= 3);
        assert!(results.iter().any(|(_, c)| c.id == "toggle_thinking"));
        assert!(results.iter().any(|(_, c)| c.id == "toggle_tool_output"));
        assert!(results.iter().any(|(_, c)| c.id == "toggle_hook_mode"));
    }

